import { unstable_cache } from 'next/cache';

export type Post = {
  id: string;
  title: string;
  content: string;
  createdAt: string;
};

// This is deliberately kept server-side. Replace this store with the application's
// database in production; the cache/invalidation contract remains the same.
const posts: Post[] = [];

export async function insertPost(title: string, content: string): Promise<Post> {
  const post: Post = {
    id: crypto.randomUUID(),
    title,
    content,
    createdAt: new Date().toISOString(),
  };

  posts.unshift(post);
  return post;
}

const getCachedPosts = unstable_cache(
  async () => posts,
  ['posts-list'],
  { tags: ['posts'] },
);

export async function getPosts(): Promise<Post[]> {
  return getCachedPosts();
}

'use server';

import { updateTag } from 'next/cache';
import { insertPost } from './lib/posts';

export type CreatePostState = {
  error?: string;
  success?: boolean;
};

export async function createPost(
  _previousState: CreatePostState,
  formData: FormData,
): Promise<CreatePostState> {
  const title = formData.get('title');
  const content = formData.get('content');

  if (typeof title !== 'string' || !title.trim()) {
    return { error: 'A title is required.' };
  }

  if (typeof content !== 'string' || !content.trim()) {
    return { error: 'Content is required.' };
  }

  await insertPost(title.trim(), content.trim());

  // updateTag, unlike revalidateTag('posts', 'max'), expires the entry
  // immediately. The next render blocks for fresh data (read-your-own-writes).
  updateTag('posts');

  return { success: true };
}

'use client';

import { useActionState } from 'react';
import { createPost, type CreatePostState } from './actions';

const initialState: CreatePostState = {};

export function CreatePostForm() {
  const [state, formAction, pending] = useActionState(createPost, initialState);

  return (
    <form action={formAction}>
      <label htmlFor="title">Title</label>
      <input id="title" name="title" required />

      <label htmlFor="content">Content</label>
      <textarea id="content" name="content" required rows={5} />

      <button type="submit" disabled={pending}>
        {pending ? 'Creating…' : 'Create post'}
      </button>

      {state.error && <p role="alert">{state.error}</p>}
      {state.success && <p role="status">Post created.</p>}
    </form>
  );
}

import { CreatePostForm } from './create-post-form';
import { getPosts } from './lib/posts';

export default async function Home() {
  const posts = await getPosts();

  return (
    <main>
      <h1>Posts</h1>
      <CreatePostForm />

      <section aria-label="Posts list">
        <h2>Latest posts</h2>
        {posts.length === 0 ? (
          <p>No posts yet.</p>
        ) : (
          <ul>
            {posts.map((post) => (
              <li key={post.id}>
                <h3>{post.title}</h3>
                <p>{post.content}</p>
              </li>
            ))}
          </ul>
        )}
      </section>
    </main>
  );
}
